# solution.py

import threading
import queue
import json
import matplotlib.pyplot as plt

class DataStore:
    def __init__(self):
        self.data = {}
        self.lock = threading.Lock()

    def add_data(self, key, value):
        with self.lock:
            if key in self.data:
                self.data[key].append(value)
            else:
                self.data[key] = [value]

    def get_data(self, key):
        with self.lock:
            return self.data.get(key, [])

class Analyst:
    def __init__(self, name, data_store):
        self.name = name
        self.data_store = data_store

    def input_data(self, key, value):
        self.data_store.add_data(key, value)
        print(f"{self.name} added data: {key} -> {value}")

    def generate_report(self):
        report = {}
        for key, values in self.data_store.data.items():
            report[key] = {
                "average": sum(values) / len(values),
                "max": max(values),
                "min": min(values)
            }
        print(f"Report generated by {self.name}: {json.dumps(report, indent=2)}")
        return report

    def generate_visualization(self, key):
        values = self.data_store.get_data(key)
        plt.figure(figsize=(10, 5))
        plt.plot(values, label=key)
        plt.title(f"Performance Metrics for {key}")
        plt.xlabel("Time")
        plt.ylabel("Value")
        plt.legend()
        plt.show()

class CollaborationManager:
    def __init__(self):
        self.data_store = DataStore()
        self.analysts = []

    def add_analyst(self, analyst):
        self.analysts.append(analyst)

    def start_collaboration(self):
        for analyst in self.analysts:
            threading.Thread(target=self._run_analyst, args=(analyst,)).start()

    def _run_analyst(self, analyst):
        # Simulate data input
        analyst.input_data("speed", 23)
        analyst.input_data("accuracy", 85)
        analyst.generate_report()
        analyst.generate_visualization("speed")

if __name__ == "__main__":
    collaboration_manager = CollaborationManager()
    analyst1 = Analyst("Analyst1", collaboration_manager.data_store)
    analyst2 = Analyst("Analyst2", collaboration_manager.data_store)
    collaboration_manager.add_analyst(analyst1)
    collaboration_manager.add_analyst(analyst2)
    collaboration_manager.start_collaboration()
```

